// GET /api/posts?limit=20&after=<cursor>

const MAX_LIMIT = 100;
const DEFAULT_LIMIT = 20;

/**
 * Encode a compound cursor (created_at, id) as an opaque base64 JSON string.
 */
function encodeCursor(row) {
    const payload = {
        // created_at may be a Date object; serialize as ISO string for stability
        createdAt: row.created_at instanceof Date
            ? row.created_at.toISOString()
            : row.created_at,
        id: row.id,
    };
    return Buffer.from(JSON.stringify(payload), 'utf8').toString('base64');
}

/**
 * Decode an opaque cursor back into { createdAt, id }.
 * Throws on any malformed / tampered input so the caller can return 400.
 */
function decodeCursor(cursor) {
    let payload;
    try {
        const json = Buffer.from(cursor, 'base64').toString('utf8');
        payload = JSON.parse(json);
    } catch (err) {
        throw new Error('Invalid cursor: not decodable');
    }

    if (
        !payload ||
        typeof payload !== 'object' ||
        typeof payload.createdAt !== 'string' ||
        payload.id === undefined ||
        payload.id === null
    ) {
        throw new Error('Invalid cursor: missing fields');
    }

    // Validate the timestamp is a real date
    const ts = new Date(payload.createdAt);
    if (Number.isNaN(ts.getTime())) {
        throw new Error('Invalid cursor: bad timestamp');
    }

    return { createdAt: payload.createdAt, id: payload.id };
}

async function getPosts(req, res) {
    // Clamp limit to a sane range
    let limit = parseInt(req.query.limit, 10) || DEFAULT_LIMIT;
    if (limit < 1) limit = DEFAULT_LIMIT;
    if (limit > MAX_LIMIT) limit = MAX_LIMIT;

    const { after } = req.query;

    let sql;
    let params;

    if (after) {
        let cursor;
        try {
            cursor = decodeCursor(after);
        } catch (err) {
            return res.status(400).json({ error: 'Invalid pagination cursor' });
        }

        // Compound cursor comparison. Sort is (created_at DESC, id DESC),
        // so "next page" = rows strictly *before* the cursor in that order.
        // The row-value comparison `(created_at, id) < ($1, $2)` is exactly
        // the tuple semantics we want and is index-friendly.
        sql = `
            SELECT id, title, content, author_id, created_at
            FROM posts
            WHERE published = true
              AND (created_at, id) < ($2, $3)
            ORDER BY created_at DESC, id DESC
            LIMIT $1
        `;
        // Fetch limit + 1 (N+1 trick) to detect whether more pages exist.
        params = [limit + 1, cursor.createdAt, cursor.id];
    } else {
        // First page: no cursor filter.
        sql = `
            SELECT id, title, content, author_id, created_at
            FROM posts
            WHERE published = true
            ORDER BY created_at DESC, id DESC
            LIMIT $1
        `;
        params = [limit + 1];
    }

    const result = await db.query(sql, params);
    const rows = result.rows;

    // N+1 trick: if we got back more than `limit`, there's another page.
    const hasMore = rows.length > limit;
    const posts = hasMore ? rows.slice(0, limit) : rows;

    const nextCursor = hasMore
        ? encodeCursor(posts[posts.length - 1])
        : null;

    res.json({
        posts,
        pagination: {
            hasMore,
            nextCursor,
            limit,
        },
    });
}

module.exports = { getPosts, encodeCursor, decodeCursor };
```

## Key implementation notes

- **Tuple comparison `(created_at, id) < ($2, $3)`** — PostgreSQL evaluates row-value constructors with proper lexicographic semantics, which is exactly the compound-cursor logic you want. It's equivalent to `created_at < $2 OR (created_at = $2 AND id < $3)` but cleaner and lets the planner use a composite index. For best performance, add: `CREATE INDEX ON posts (created_at DESC, id DESC) WHERE published = true;`
- **`$1` is always `limit + 1`** — the N+1 trick. We slice back down to `limit` before responding and use the extra row only as a "has-more" signal.
- **Opaque cursor** — base64-encoded JSON keeps the client from depending on internal column structure, so you can change the cursor shape later without breaking clients. Decoding is wrapped so any malformed/tampered value yields a clean `400`.
- **No `OFFSET`, no `COUNT`** — per requirements.

## Why cursor-based pagination is superior here

1. **Stable performance at depth.** `OFFSET 100000 LIMIT 20` forces Postgres to scan and discard 100,000 rows before returning 20 — cost grows linearly with page depth. A cursor `WHERE (created_at, id) < (...)` does an index seek straight to the right spot: roughly **O(log n)** regardless of how deep you page.
2. **No skipped/duplicated rows under writes.** With offset pagination, if a new post is inserted (or one is deleted) between requests, the absolute offsets shift and the client sees a row twice or misses one. The cursor anchors to a specific `(created_at, id)` position, so the boundary stays correct as the table changes — important here since posts are ordered by `created_at DESC` and new posts arrive at the top.
3. **Drops the expensive `COUNT(*)`.** On large tables a full `COUNT` of published posts is a costly scan run on every page request; `hasMore` from the N+1 trick gives the client what it actually needs to drive "load more" UI without it.

The main trade-off: you lose random access to arbitrary page numbers (no "jump to page 50") and total counts. For an infinite-scroll / "load more" feed ordered by recency, that's exactly the access pattern you want, so the trade is worth it.

