## Cursor-Based Pagination Implementation

```javascript
// ─── Cursor Helpers ───────────────────────────────────────────────────────────

/**
 * Encodes a (created_at, id) pair into an opaque base64 cursor string.
 * @param {Date|string} created_at
 * @param {number} id
 * @returns {string} base64-encoded cursor
 */
function encodeCursor(created_at, id) {
    const payload = {
        created_at: new Date(created_at).toISOString(),
        id: Number(id),
    };
    return Buffer.from(JSON.stringify(payload), 'utf8').toString('base64');
}

/**
 * Decodes a base64 cursor string back into { created_at, id }.
 * Returns null if the cursor is missing, malformed, or logically invalid —
 * caller must treat null as a 400 error.
 * @param {string} cursorStr
 * @returns {{ created_at: Date, id: number } | null}
 */
function decodeCursor(cursorStr) {
    try {
        const raw = Buffer.from(cursorStr, 'base64').toString('utf8');
        const payload = JSON.parse(raw);

        // Structural validation
        if (typeof payload !== 'object' || payload === null) return null;
        if (!('created_at' in payload) || !('id' in payload)) return null;

        const created_at = new Date(payload.created_at);
        if (isNaN(created_at.getTime())) return null;  // reject bad dates

        const id = Number(payload.id);
        if (!Number.isInteger(id) || id <= 0) return null;  // reject bad ids

        return { created_at, id };
    } catch {
        // JSON.parse failure, Buffer failure, etc.
        return null;
    }
}

// ─── Route Handler ────────────────────────────────────────────────────────────

// GET /api/posts?limit=20&after=<cursor>
async function getPosts(req, res) {
    // --- Parse & validate limit ---
    const MAX_LIMIT = 100;
    const limit = Math.min(
        Math.max(parseInt(req.query.limit, 10) || 20, 1),
        MAX_LIMIT
    );

    // --- Parse & validate cursor ---
    let cursor = null;
    if (req.query.after !== undefined) {
        cursor = decodeCursor(req.query.after);
        if (cursor === null) {
            return res.status(400).json({
                error: 'Invalid cursor. The `after` parameter is malformed or expired.',
            });
        }
    }

    // --- Build query (fetch limit + 1 to detect hasMore) ---
    let result;

    if (cursor) {
        // Rows that come *after* the cursor in a (created_at DESC, id DESC) sort:
        // Any row where created_at is older than the cursor's, OR same timestamp
        // but a smaller id. PostgreSQL's ROW comparison handles this exactly:
        //   (a, b) < (c, d)  ≡  a < c  OR (a = c AND b < d)
        result = await db.query(
            `SELECT id, title, content, author_id, created_at
               FROM posts
              WHERE published = true
                AND (created_at, id) < ($1::timestamptz, $2::int)
              ORDER BY created_at DESC, id DESC
              LIMIT $3`,
            [cursor.created_at.toISOString(), cursor.id, limit + 1]
        );
    } else {
        // First page — no cursor filter at all
        result = await db.query(
            `SELECT id, title, content, author_id, created_at
               FROM posts
              WHERE published = true
              ORDER BY created_at DESC, id DESC
              LIMIT $1`,
            [limit + 1]
        );
    }

    // --- Apply LIMIT+1 trick ---
    const rows = result.rows;
    const hasMore = rows.length > limit;       // got the sentinel row → more exist
    const posts = hasMore ? rows.slice(0, limit) : rows;  // drop sentinel

    // --- Build next cursor from last row that will actually be returned ---
    const lastPost = posts.at(-1);  // undefined when posts is empty
    const nextCursor =
        hasMore && lastPost
            ? encodeCursor(lastPost.created_at, lastPost.id)
            : null;

    res.json({
        posts,
        pagination: {
            hasMore,
            nextCursor,  // null when on the last page
            limit,
        },
    });
}
```

